                <div class="ap-calc-result-title">Estimated Service Fee:</div>
                <div class="ap-calc-amount" id="ap-fee-display">₹225</div>
                <div style="font-size: 0.8rem; color: var(--text-muted); margin-top: 0.5rem;" id="ap-fee-note">
