        <label for="tn-certified" style="font-size:0.9rem; color:#334155; font-weight:600; cursor:pointer;">டிஜிட்டல் கையொப்பமிட்ட சான்றளிக்கப்பட்ட நகல் வேண்டும் (+ ₹100)</label>
    </div>
    
    <button type="button" onclick="calculateTamilTNFees()" style="width:100%; padding:0.75rem; font-size:1rem; border-radius:6px; background-color:var(--primary); color:#ffffff; font-weight:600; border:none; cursor:pointer; margin-bottom:1.5rem;">
        அரசு கட்டணத்தைக் கணக்கிடுக
    </button>
    
    <div id="tn-calculator-result" style="display:none; padding:1.25rem; border-radius:8px; border:1px solid var(--border);">
        <!-- Filled dynamically -->
    </div>
</div>

<script>
function calculateTamilTNFees() {
    var start = parseInt(document.getElementById("tn-start-year").value);
    var end = parseInt(document.getElementById("tn-end-year").value);
    var certified = document.getElementById("tn-certified").checked;
    var resultBox = document.getElementById("tn-calculator-result");
    
    if (isNaN(start) || isNaN(end) || start > end || start < 1975 || end > 2026) {
        alert("தயவுசெய்து சரியான ஆண்டுகளை உள்ளிடவும் (1975-2026).");
        return;
    }
    
    var totalYears = end - start + 1;
    var searchFee = 15; // base fee first year
    if (totalYears > 1) {
        searchFee += (totalYears - 1) * 5; // subsequent years
    }
    
    var copyFee = certified ? 100 : 0;
    var totalFee = searchFee + copyFee;
    
    resultBox.style.display = "block";
    resultBox.style.backgroundColor = "#f8fafc";
    resultBox.style.borderColor = "var(--border)";
    
    resultBox.innerHTML = "<div style=\\"font-weight:700; color:var(--primary); margin-bottom:0.75rem; font-size:1.1rem;\\">மதிப்பிடப்பட்ட அரசு கட்டண விவரங்கள்:</div>" +
        "<div style=\\"font-size:0.95rem; color:#334155; line-height:1.6;\\">" +
            "<div><strong>தேடப்படும் காலம்:</strong> " + totalYears + " வருடங்கள்</div>" +
            "<div><strong>அடிப்படை தேடல் கட்டணம் (முதல் வருடம்):</strong> ₹15</div>" +
            "<div><strong>இதர வருடங்களின் தேடல் கட்டணம் (வருடத்திற்கு ₹5):</strong> ₹" + (totalYears > 1 ? (totalYears - 1) * 5 : 0) + "</div>" +
            "<div><strong>விண்ணப்ப மற்றும் நகல் கட்டணங்கள்:</strong> ₹" + copyFee + "</div>" +
            "<div style=\\"border-top:1px solid var(--border); margin-top:0.75rem; padding-top:0.75rem; font-size:1.1rem; font-weight:700; color:#0f172a;\\">" +
                "மொத்த கட்டணம்: ₹" + totalFee + 
            "</div>" +
            "<div style=\\"font-size:0.8rem; color:#64748b; margin-top:0.5rem; font-style:italic;\\">குறிப்பு: சான்றொப்பம் இல்லாமல் கணினியில் மட்டும் பார்க்க கட்டணம் ஏதும் செலுத்த வேண்டியதில்லை.</div>" +
        "</div>";
}
</script>

<h2>ஆன்லைனில் வில்லங்க சான்றிதழ் பார்ப்பது எப்படி? - எளிய வழிமுறைகள்</h2>
<p class="content-text">
    தமிழ்நாடு பதிவுத்துறையின் அதிகாரப்பூர்வ இணையதளம் மூலம் வில்லங்கத்தைச் சரிபார்க்கும் செயல்முறை கீழே விவரிக்கப்பட்டுள்ளது. பொதுமக்கள் பதிவுத்துறையில் எளிய முறையில் <a href="https://econline.in/">ec online</a> தேடல் செய்ய முடியும்.
</p>

<h3>வழிமுறை 1: அதிகாரப்பூர்வ இணையதளத்தை அணுகவும்</h3>
<p class="content-text">
    தமிழக அரசின் பதிவுத்துறை இணையதளமான <strong>tnreginet.gov.in</strong> என்ற முகவரிக்குச் செல்லவும். முகப்புப் பக்கத்தின் மேல் பகுதியில் உள்ள மெனுவில் <strong>"மின்னணு சேவைகள்" (E-Services)</strong> என்ற விருப்பத்தைத் தேர்வுசெய்யவும். அதில் <strong>"வில்லங்கச் சான்றிதழ்" (Encumbrance Certificate)</strong> → <strong>"வில்லங்கச் சான்றிதழ் விவரங்களைப் பார்வையிடுதல்" (View EC)</strong> என்பதை சொடுக்கவும்.
</p>

<h3>வழிமுறை 2: சொத்து விவரங்கள் அல்லது ஆவண விவரங்களை உள்ளிடுதல்</h3>
<p class="content-text">
    இங்கே தேடல் பக்கத்தில் இரண்டு தேடல் தேர்வுகள் இருக்கும்:
</p>
<ul class="guide-list">
    <li><strong>சொத்து வாரியான தேடல் (Property Wise)</strong>: சொத்து அமைந்துள்ள மாவட்டம், சார்பதிவாளர் அலுவலகம், தாலுகா, கிராமம் மற்றும் புல எண் (Survey Number) ஆகியவற்றை உள்ளிட்டுத் தேட வேண்டும்.</li>
    <li><strong>ஆவண வாரியான தேடல் (Document Wise)</strong>: சொத்தின் பத்திர ஆவண எண், சார்பதிவாளர் அலுவலகம் மற்றும் பதிவு செய்யப்பட்ட ஆண்டு ஆகியவற்றை உள்ளிட்டுத் தேட வேண்டும்.</li>
</ul>

<h3>வழிமுறை 3: புல எண் மற்றும் உட்பிரிவு எண் உள்ளிடுதல்</h3>
<p class="content-text">
    சொத்து வாரியாகத் தேடும்போது நிலத்தின் புல எண் மற்றும் உட்பிரிவு எண்ணைத் தனியாக உள்ளிட வேண்டும். புல எண்களை உள்ளிடுவதில் சிறு பிழை ஏற்பட்டாலும் தேடல் முடிவு தவறாகக் காட்டும்.
</p>

<!-- Widget 3: நில அளவை எண் சரிபார்ப்பு -->
<div class="custom-card" style="margin:2.5rem 0; padding:2rem; border-radius:12px; border:1px solid var(--border); background: linear-gradient(135deg, #fefefe 0%, #f8fafc 100%);">
    <h3 style="margin-top:0; color:#1e293b; margin-bottom:0.5rem; display:flex; align-items:center; gap:0.5rem;">
        <svg width="24" height="24" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24" style="color:var(--accent);"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" stroke-linecap="round" stroke-linejoin="round"/></svg>
        நில அளவை எண் சரிபார்ப்புக் கருவி
    </h3>
    <p class="content-text" style="font-size:0.9rem; color:var(--text-muted); margin-bottom:1.5rem;">
        உங்களின் முழு சர்வே எண்ணை (உதாரணம்: 102/4B) உள்ளிட்டு, அதை பதிவுத்துறை இணையதளத்தில் எவ்வாறு உள்ளிட வேண்டும் என்பதை அறிந்துகொள்ளுங்கள்.
    </p>
    
    <div style="margin-bottom:1rem;">
        <label style="display:block; font-weight:600; margin-bottom:0.5rem; font-size:0.85rem; color:#475569;">முழு சர்வே எண்</label>
        <input type="text" id="tamil-survey-input" value="102/4B" style="width:100%; padding:0.75rem; border-radius:6px; border:1px solid var(--border); font-size:0.95rem;">
    </div>
    
    <button type="button" onclick="formatTamilSurvey()" style="width:100%; padding:0.75rem; font-size:1rem; border-radius:6px; background-color:var(--primary); color:#ffffff; font-weight:600; border:none; cursor:pointer; margin-bottom:1.5rem;">
        சர்வே எண்ணைப் பிரிக்கவும்
    </button>
    
    <div id="tamil-survey-result" style="display:none; padding:1.25rem; border-radius:8px; border:1px solid var(--border); background-color:#ffffff;">
        <!-- Filled dynamically -->
    </div>
</div>

<script>
function formatTamilSurvey() {
    var rawInput = document.getElementById("tamil-survey-input").value.trim();
    var resultBox = document.getElementById("tamil-survey-result");
    
    if (!rawInput) {
        alert("சர்வே எண்ணை உள்ளிடவும்.");
        return;
    }
    
    var surveyPart = rawInput;
    var subdivisionPart = "";
    
    var separatorIdx = rawInput.indexOf("/");
    if (separatorIdx === -1) {
        separatorIdx = rawInput.indexOf("-");
    }
    
    if (separatorIdx !== -1) {
        surveyPart = rawInput.substring(0, separatorIdx).trim();
        subdivisionPart = rawInput.substring(separatorIdx + 1).trim();
    }
    
    resultBox.style.display = "block";
    resultBox.style.borderColor = "var(--border)";
    resultBox.style.backgroundColor = "#f8fafc";
    
    resultBox.innerHTML = "<div style=\\"font-weight:700; color:var(--primary); margin-bottom:0.5rem;\\">இணையதளப் பெட்டிகளில் உள்ளிட வேண்டிய முறை:</div>" +
        "<div style=\\"font-size:0.95rem; color:#334155; line-height:1.6;\\">" +
            "<div><strong>புல எண் (Survey Number Box):</strong> <code>" + surveyPart + "</code></div>" +
            "<div><strong>உட்பிரிவு எண் (Subdivision Number Box):</strong> <code>" + (subdivisionPart ? subdivisionPart : "இல்லை (None)") + "</code></div>" +
            "<div style=\\"margin-top:0.75rem; font-size:0.85rem; color:#64748b; font-style:italic;\\">" +
                "குறிப்பு: உட்பிரிவில் ஆங்கில எழுத்துக்கள் இருந்தால் அவற்றை பெரிய எழுத்துக்களில் (UPPERCASE) உள்ளிடவும்." +
            "</div>" +
        "</div>";
}
</script>

<h3>வழிமுறை 4: தேடலின் முடிவைப் பார்வையிடல்</h3>
<p class="content-text">
    விவரங்களை உள்ளிட்ட பின், திரையில் தோன்றும் குறியீட்டு எண்ணை (Captcha) உள்ளிட்டு <strong>"தேடுக" (Search)</strong> என்பதை அழுத்தவும். உங்கள் கணினியில் வில்லங்க சான்றிதழின் நகல் PDF வடிவில் பதிவிறக்கமாகும்.
</p>

<p class="content-text">
    பதிவுத்துறை ஆவண தேடல் பற்றி விரிவாக அறிய <a href="/online-ec-view-tamilnadu/">online ec view tamilnadu</a> அல்லது <a href="/tnreginet-ec-view-online/">tnreginet ec view online</a> பக்கங்களை வாசிக்கவும்.
</p>

<h2>வில்லங்க சான்றிதழ் கோப்பு அட்டவணையின் முக்கிய சொற்கள் (Terminology)</h2>
<p class="content-text">
    சான்றளிக்கப்பட்ட ஆவண நகலை <a href="https://econline.in/">ec online</a> முறையில் பதிவிறக்கம் செய்தவுடன், அதில் சில குறிப்பிட்ட சொற்கள் இருக்கும். அவற்றின் பொருளை நீங்கள் கட்டாயம் புரிந்து கொள்ள வேண்டும்:
</p>
<div style="overflow-x: auto; margin: 1.5rem 0;">
    <table style="width: 100%; border-collapse: collapse; text-align: left; font-size: 0.95rem; border: 1px solid var(--border);">
        <thead>
            <tr style="background-color: var(--primary); color: white;">
                <th style="padding: 12px; border: 1px solid var(--border);">சொற்கள் (Terms)</th>
                <th style="padding: 12px; border: 1px solid var(--border);">விளக்கம் / பொருள்</th>
                <th style="padding: 12px; border: 1px solid var(--border);">சொத்து மீதான தாக்கம்</th>
            </tr>
        </thead>
        <tbody>
            <tr style="background-color: #ffffff;">
                <td style="padding: 12px; border: 1px solid var(--border); font-weight: 600;">எழுதிக்கொடுத்தவர் (Executant)</td>
                <td style="padding: 12px; border: 1px solid var(--border);">நிலத்தை விற்கும் உரிமையாளர் அல்லது அடமானம் வைக்கும் நபர்.</td>
                <td style="padding: 12px; border: 1px solid var(--border);">சொத்தின் முந்தைய உரிமையாளர் யார் என்பதை உறுதிப்படுத்துகிறது.</td>
            </tr>
            <tr style="background-color: #f8fafc;">
                <td style="padding: 12px; border: 1px solid var(--border); font-weight: 600;">எழுதி வாங்கியவர் (Claimant)</td>
                <td style="padding: 12px; border: 1px solid var(--border);">சொத்தை வாங்குபவர் அல்லது கடன் வழங்கிய வங்கி.</td>
                <td style="padding: 12px; border: 1px solid var(--border);">சொத்து தற்போது யாரிடம் கைமாறியுள்ளது என்பதைக் காட்டுகிறது.</td>
            </tr>
            <tr style="background-color: #ffffff;">
                <td style="padding: 12px; border: 1px solid var(--border); font-weight: 600;">Nil Encumbrance</td>
                <td style="padding: 12px; border: 1px solid var(--border);">தேடப்பட்ட காலத்தில் எந்தவிதப் பத்திரப்பதிவு பரிவர்த்தனைகளும் நடைபெறவில்லை.</td>
                <td style="padding: 12px; border: 1px solid var(--border);">சொத்தின் மீது தற்போதைக்கு கடன் பொறுப்புகள் அல்லது வில்லங்கங்கள் ஏதும் இல்லை.</td>
            </tr>
        </tbody>
    </table>
</div>

<p class="content-text">
    இணையதளம் மூலம் பிற தென்னிந்திய மாநில ஆவணங்களைத் தேட, எங்களின் <a href="/online-ec-check/">online ec check</a> வழிகாட்டிப்பக்கத்தைப் பயன்படுத்தவும் அல்லது <a href="/ec-online-tamil/">ec online tamil</a> கட்டுரையைப் படிக்கவும்.
</p>

<h2>சொத்து வாங்கும் போது கவனிக்க வேண்டிய முக்கிய எச்சரிக்கைகள்</h2>
<p class="content-text">
    வில்லங்க சான்றிதழில் எந்தப் பதிவும் இல்லை (Nil Encumbrance) என்று வந்தால் மட்டுமே அந்த சொத்து சுத்தமானது என்று முழுமையாக நம்பிவிடக் கூடாது. சொத்தின் தற்போதைய நிலையை அறிய <a href="https://econline.in/">ec online</a> சரிபார்ப்பு மிகவும் அவசியமான ஒன்றாகும். கூடுதல் பாதுகாப்பிற்காக பின்வரும் சோதனைகளையும் செய்ய வேண்டும்:
</p>
<ol style="margin-left: 2rem; color: #475569; margin-bottom: 1.5rem;">
    <li style="margin-bottom: 0.5rem;"><strong>30 வருட வில்லங்கம் சரிபார்த்தல்</strong>: பொதுவாக வங்கிகள் 15 வருட தேடல் விவரங்களைக் கேட்டாலும், சொத்தின் முந்தைய வாரிசுரிமை சிக்கல்களைத் தவிர்க்க குறைந்தது 30 வருட வில்லங்கத்தை சரிபார்ப்பது நல்லது.</li>
    <li style="margin-bottom: 0.5rem;"><strong>பட்டா மாறுதல் ஆவணம்</strong>: சொத்தின் பட்டா விற்பனையாளரின் பெயரில் தற்போதும் உள்ளதா என்பதை தமிழ்நாடு வருவாய்த் துறையின் இணையதளத்தில் (eservices.tn.gov.in) சரிபார்க்க வேண்டும்.</li>
