<script>
function calcEcoFee() {
    var y = parseInt(document.getElementById("eco-years").value);
    var state = document.getElementById("eco-fee-type").value;
    var box = document.getElementById("eco-fee-box");
    if (isNaN(y) || y < 1) { box.style.display = "none"; return; }
    var base = 0;
    var additional = 0;
    var processing = 0;
    if (state === "tn") {
        base = 30; additional = (y > 1) ? (y - 1) * 10 : 0; processing = 20;
    } else if (state === "ka") {
        base = 60; additional = (y > 1) ? (y - 1) * 30 : 0; processing = 40;
    } else {
        base = 200; additional = (y > 1) ? (y - 1) * 100 : 0; processing = 50;
    }
    var total = base + additional + processing;
    box.style.display = "block";
    box.style.backgroundColor = "hsl(260, 80%, 97%)";
    box.style.borderColor = "hsl(260, 80%, 87%)";
    box.innerHTML = "<div style=\"font-weight:700;color:hsl(260,70%,22%);margin-bottom:0.75rem;\">Statutory Fee Breakup:</div>" +
        "<div style=\"font-size:0.95rem;color:#334155;line-height:1.8;\">" +
        "<div><strong>First Year Search Fee:</strong> \u20B9" + base + "</div>" +
        "<div><strong>Additional Years Fee:</strong> \u20B9" + additional + "</div>" +
        "<div><strong>Portal Application Fee:</strong> \u20B9" + processing + "</div>" +
        "<div style=\"border-top:1px solid hsl(260, 80%, 87%);margin-top:0.75rem;padding-top:0.75rem;font-weight:700;font-size:1.05rem;color:hsl(260,70%,20%);\">Total Fee Estimate: \u20B9" + total + "</div></div>";
}
document.addEventListener("DOMContentLoaded", function() {
    if (document.getElementById("eco-years")) calcEcoFee();
});
</script>

