<script>
function calcEioYears() {
    var y = parseInt(document.getElementById("eio-years-inp").value) || 0;
    var r = document.getElementById("eio-years-result");
    if (1 > y) { r.innerHTML = "Please enter valid years."; return; }
    var today = new Date();
    var past = new Date();
